config.handler:
this.frmDC_tipoContratante = "PN";
this.frmDC_rutContratante = null;
this.frmDC_rutContratante_aux = "";
this.frmDC_nombreContratante = null;
this.frmDC_nombreContratante_cal = "";
this.frmDC_apellidoContratante = null;
this.frmDC_apellidoContratante_cal = "";
this.frmDC_correoContratante = null;
this.frmDC_ciudadContratante = null;
this.frmDC_municipalityContratante = null;
this.frmDC_direccionContratante = null;
this.frmDC_telefonoContratante = "";
this.frm_cliente_response = null;

computed.formula:
const frmDC_rutContratante = this.frmDC_rutContratante;
let partes = "";
let rut_p = "";
let result = "";

if(frmDC_rutContratante) {
    partes = frmDC_rutContratante.trim().split("-");
    rut_p = partes[0];
    result = frmDC_rutContratante.length === 9 || frmDC_rutContratante.length === 10 ? rut_p : "";
}

return result;

const res_error = this.frm_cliente_response?.error ?? '';
const res_result = this.frm_cliente_response?.result ?? '';
let hayResultado = false;

if (!res_error && res_result > 0) {
  hayResultado = true;
}

// Resultado final de la propiedad
const result = hayResultado ? true : false;

// Devolvemos el flag en STRING
return result;

if (this.frmDC_rutContratante === '') {
  return '';
}

const name = this.frm_cliente_response?.name ?? '';

if(name) {
    return name;
}

const tipoContratante = this.frmDC_tipoContratante;
let nombreContratanteLabel = "Nombre o Razón Social";

if(tipoContratante) {
    if(tipoContratante == "PN") {
        nombreContratanteLabel = "Nombre";
    } else {
        nombreContratanteLabel = "Razón Social";
    }
}

return nombreContratanteLabel;

if (this.frmDC_rutContratante === '') {
  return '';
}

const lastName = this.frm_cliente_response?.lastName ?? '';

if(lastName) {
    return lastName;
}

const resp_acc = this.frm_cliente_response_accion;
const tc = this.frmDC_tipoContratante;

let visibilidad = false;

if(resp_acc == true && tc == "PN")
{
    visibilidad = true;
}

return visibilidad;

const resp_acc = this.frm_cliente_response_accion;
const tc = this.frmDC_tipoContratante;

let visibilidad = false;

if(resp_acc !== true && tc == "PN")
{
    visibilidad = true;
}

return visibilidad;

screens.custom_css:
[selector="btn_consultar"] .btn {
    font-weight: 600;
    border-radius: 6px;
    padding: .35rem .9rem;
    margin: 23px -10px 10px 0;
    position: relative;
    padding-left: 2rem;
}

[selector="btn_consultar"] .btn::before {
    content: "\f002";               /* código de icono de búsqueda */
    font-family: "Font Awesome 5 Free";
    font-weight: 900;               /* sólido */
    position: absolute;
    left: .6rem;
    top: 50%;
    transform: translateY(-50%);
    font-size: 0.9rem;
}

[selector="btn_limpiar"] .btn {
    font-weight: 600;
    border-radius: 6px;
    padding: .35rem .9rem;
    margin: 23px -10px 10px 0;
    position: relative;
    padding-left: 2rem;
}

[selector="btn_limpiar"] .btn::before {
    content: "\f12d";               /* código de icono de búsqueda */
